from itertools import permutations

class Solution:
    def minCost(self, arr, brr, k):
        n = len(arr)
        direct = sum(abs(a - b) for a, b in zip(arr, brr))
        best = direct
        if n <= 7:
            for perm in set(permutations(arr)):
                cost = 0 if list(perm) == list(arr) else k
                cost += sum(abs(a - b) for a, b in zip(perm, brr))
                if cost < best:
                    best = cost
        else:
            sorted_arr = sorted(arr)
            sorted_brr = sorted(brr)
            rearranged = k + sum(abs(a - b) for a, b in zip(sorted_arr, sorted_brr))
            best = min(best, rearranged)
        return best

