var minCost = function(arr, brr, k) {
    let direct = 0;
    for (let i = 0; i < arr.length; i++) direct += Math.abs(arr[i] - brr[i]);
    const sortedArr = arr.slice().sort((a, b) => a - b);
    const sortedBrr = brr.slice().sort((a, b) => a - b);
    let rearranged = k;
    for (let i = 0; i < sortedArr.length; i++) rearranged += Math.abs(sortedArr[i] - sortedBrr[i]);
    return Math.min(direct, rearranged);
};
